export default function MovieCard({ title, rating, year, genre }) {
  return (
    <div className="group min-w-[140px] md:min-w-[180px] cursor-pointer">
      {/* Poster Image Area */}
      <div className="w-full h-[210px] md:h-[270px] bg-surface rounded-[20px] overflow-hidden relative transition-all duration-300 group-hover:-translate-y-1.5 group-hover:shadow-[0_12px_32px_rgba(0,0,0,0.35)] border border-white/5">
        <div className="absolute inset-0 flex items-center justify-center text-text-secondary">
          Poster
        </div>
        {/* Play Button Overlay (Muncul saat di-hover) */}
        <div className="absolute inset-0 bg-black/40 opacity-0 group-hover:opacity-100 transition duration-300 flex items-center justify-center">
          <div className="w-10 h-10 rounded-full bg-white/20 backdrop-blur-md flex items-center justify-center border border-white/30">
            ▶
          </div>
        </div>
      </div>

      {/* Teks Info Film */}
      <div className="mt-3">
        <h3 className="text-base font-medium text-text-main truncate">{title}</h3>
        <div className="flex items-center gap-2 text-[12px] text-text-secondary mt-1">
          <span className="text-yellow-500">★ {rating}</span>
          <span>{year}</span>
        </div>
        <p className="text-[12px] text-text-secondary mt-0.5 truncate">{genre}</p>
      </div>
    </div>
  );
}